std::vector<std::string> buildXyceArgs(
    const std::string& netlistFile,
    const std::string& outputFile,
    const std::vector<std::string>& pluginLibraries
) {
    std::vector<std::string> args;
    args.push_back("Xyce");
    for (const auto& plugin : pluginLibraries) {
        if (!plugin.empty()) {
            args.push_back("-plugin");
            args.push_back(plugin);
        }
    }
    if (!outputFile.empty()) {
        args.push_back("-o");
        args.push_back(outputFile);
    }
    args.push_back(netlistFile);
    return args;
}

Xyce::Circuit::Simulator::RunStatus initializeWithArgs(
    Xyce::Circuit::Simulator& xyce,
    const std::vector<std::string>& args
) {
    std::vector<char*> argv;
    argv.reserve(args.size());

    for (const auto& arg : args) {
        argv.push_back(const_cast<char*>(arg.c_str()));
    }

    return xyce.initialize(static_cast<int>(argv.size()), argv.data());
}

bool isSuccessStatus(Xyce::Circuit::Simulator::RunStatus status) {
    return status == Xyce::Circuit::Simulator::SUCCESS || status == Xyce::Circuit::Simulator::DONE;
}

bool fileExists(const std::string& path) {
    std::ifstream f(path);
    return f.good();
}

std::string canonicalizeIfExists(const std::string& path) {
    if (!fileExists(path)) {
        return "";
    }

    char resolved[PATH_MAX];
    if (realpath(path.c_str(), resolved) != nullptr) {
        return std::string(resolved);
    }
    return path;
}

std::string executableDirectory() {
    char exePath[PATH_MAX];
    ssize_t len = readlink("/proc/self/exe", exePath, sizeof(exePath) - 1);
    if (len <= 0) {
        return "";
    }
    exePath[len] = '\0';
    return Utils::directoryName(std::string(exePath));
}

std::string makeAbsolutePath(const std::string& path) {
    if (path.empty() || path[0] == '/') {
        const std::string canonical = canonicalizeIfExists(path);
        return canonical.empty() ? path : canonical;
    }

    char cwd[PATH_MAX];
    if (getcwd(cwd, sizeof(cwd)) != nullptr) {
        const std::string fromCwd = Utils::joinPath(std::string(cwd), path);
        const std::string canonical = canonicalizeIfExists(fromCwd);
        if (!canonical.empty()) {
            return canonical;
        }
    }

    const std::string exeDir = executableDirectory();
    if (!exeDir.empty()) {
        const std::string fromExeDir = Utils::joinPath(exeDir, path);
        const std::string canonical = canonicalizeIfExists(fromExeDir);
        if (!canonical.empty()) {
            return canonical;
        }
    }

    if (getcwd(cwd, sizeof(cwd)) == nullptr) {
        return path;
    }
    return Utils::joinPath(std::string(cwd), path);
}

std::string detectGeneratedPrn(const std::string& netlistFile, const std::string& outputSuffix) {
    if (netlistFile.empty()) {
        return "";
    }

    const std::string netlistDir = Utils::directoryName(netlistFile);
    std::string base = netlistFile;
    const std::size_t lastSlash = base.find_last_of('/');
    if (lastSlash != std::string::npos && lastSlash + 1 < base.size()) {
        base = base.substr(lastSlash + 1);
    }

    const std::size_t lastDot = base.find_last_of('.');
    if (lastDot != std::string::npos) {
        base = base.substr(0, lastDot);
    }

    std::vector<std::string> candidates;
    if (!outputSuffix.empty()) {
        candidates.push_back(Utils::joinPath(netlistDir, base + outputSuffix + ".prn"));
    }
    candidates.push_back(Utils::joinPath(netlistDir, base + ".prn"));
    candidates.push_back(Utils::joinPath(netlistDir, "xyce_output.prn"));

    for (const auto& candidate : candidates) {
        if (fileExists(candidate)) {
            return candidate;
        }
    }

    return candidates.empty() ? "" : candidates.front();
}

std::string ensureTrailingNewline(const std::string& value) {
    if (value.empty() || value.back() == '\n') {
        return value;
    }
    return value + "\n";
}

