bool XyceSimulator::loadNetlistFromFile(const std::string& filepath) {
    try {
        pimpl_->netlist_file = makeAbsolutePath(filepath);
        pimpl_->netlist_loaded = true;
        pimpl_->engine = "XyceSolver";

        if (pimpl_->verbose) {
            std::cout << "[" << pimpl_->engine << "] Loading netlist from: " << filepath << std::endl;
        }

        return true;

    } catch (const std::exception& e) {
        last_error_ = std::string("Failed to load netlist: ") + e.what();
        std::cerr << "[" << pimpl_->engine << "] Error: " << last_error_ << std::endl;
        return false;
    }
}

bool XyceSimulator::loadNetlistFromString(const std::string& netlist_content) {
    try {
        const std::string prelude = getCustomPrelude();
        const std::string merged_netlist = prelude.empty() ? netlist_content : prelude + "\n" + netlist_content;

        std::string temp_file = "/tmp/xyce_netlist_" + 
                               std::to_string(std::hash<std::string>{}(merged_netlist)) + 
                               ".cir";

        std::ofstream ofs(temp_file);
        if (!ofs.is_open()) {
            last_error_ = "Failed to create temporary netlist file";
            std::cerr << "[" << pimpl_->engine << "] Error: " << last_error_ << std::endl;
            return false;
        }

        ofs << merged_netlist;
        ofs.close();

        pimpl_->netlist_file = temp_file;
        pimpl_->netlist_string = merged_netlist;
        pimpl_->netlist_loaded = true;
        pimpl_->engine = "Xyce";

        if (pimpl_->verbose) {
            std::cout << "[" << pimpl_->engine << "] Loading netlist from string (" 
                      << merged_netlist.length() << " chars)" << std::endl;
        }

        return true;

