/* STAR SHAPE: filled star (includes inner pentagon) using ear clipping */
void starPolygon(float cx, float cy, float outerR, float innerR, float rotRad)
{
	float ox[5], oy[5];   // outer tips
	float ix[5], iy[5];   // inner corners

	// Build points:
	// outer angles: rot + k*72°
	// inner angles: rot + 36° + k*72°
	for (int k = 0; k < 5; k++) {
		float aO = rotRad + k * (2.0 * PI / 5.0);          // 72°
		float aI = rotRad + (PI / 5.0) + k * (2.0 * PI / 5.0); // 36° shift

		ox[k] = cx + outerR * cosf(aO);
		oy[k] = cy + outerR * sinf(aO);

		ix[k] = cx + innerR * cosf(aI);
		iy[k] = cy + innerR * sinf(aI);
	}

	// 1) Draw 5 triangles (the star arms)
	glBegin(GL_TRIANGLES);
	for (int k = 0; k < 5; k++) {
		int prev = (k + 4) % 5;   // inner point on left side of this arm
		int next = (k + 1) % 5;   // inner point on right side of this arm

		// Triangle: inner-left -> outer-tip -> inner-right
		glVertex2f(ix[prev], iy[prev]);
		glVertex2f(ox[k], oy[k]);
		glVertex2f(ix[next], iy[next]);
	}
	glEnd();

	// 2) Fill the inner pentagon (connect inner points in order)
	glBegin(GL_POLYGON);
	for (int k = 0; k < 5; k++)
		glVertex2f(ix[k], iy[k]);
	glEnd();
}


